examples.source:
for (let i = 1; i <= 5; i++) {
  console.log("الدورة رقم " + i);
}

let sum = 0;
for (let i = 1; i <= 100; i++) {
  sum += i;
}
console.log("مجموع 1 إلى 100 =", sum);

let n = 3;
while (n > 0) {
  console.log("while:", n);
  n--;
}

let x = 0;
do {
  console.log("do-while تنفذ مرة رغم خيبة الشرط، x =", x);
} while (x > 5);

const fruits = ["تفاح", "موز", "عنب"];
for (const fruit of fruits) {
  console.log(fruit);
}

const user = { name: "سالم", age: 25 };
for (const key in user) {
  console.log(key + ": " + user[key]);
}

for (let i = 1; i <= 10; i++) {
  if (i === 6) {
    console.log("وجدت 6 — أخرج نهائيًا");
    break;
  }
  if (i % 2 !== 0) continue; // تجاهل الفردي
  console.log("زوجي:", i);
}
